// Parse AI response and return only relevant documents
const aiResponse = $('AI Filter Documents').first().json;
const prepData = $('Prepare for AI Filter').first().json;
const context = $('Extract Context').first().json;
const allDocs = prepData.all_docs;

let aiText = aiResponse.message?.content || aiResponse.text || '';

// Strip markdown code fences if present
aiText = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(aiText);
} catch (e) {
  // Fallback: try to extract indices from the text
  const matches = aiText.match(/\d+/g);
  parsed = {
    relevant_indices: matches ? matches.map(Number) : [],
    reasoning: { fallback: 'Could not parse AI response, extracted indices from text' }
  };
}

const relevantIndices = parsed.relevant_indices || [];
const reasoning = parsed.reasoning || {};

const relevantDocs = {};
const missingTypes = [];

for (const idx of relevantIndices) {
  if (idx >= 0 && idx < allDocs.length) {
    const doc = allDocs[idx];
    const category = doc.ai_category || doc.category || 'other';
    relevantDocs[category] = {
      found: true,
      id: doc.id,
      fileName: doc.name,
      category: category,
      extractedText: doc.extracted_text || '',
      extractionStatus: doc.extraction_status,
      createdAt: doc.created_at,
      relevanceReason: reasoning[String(idx)] || 'Selected by AI'
    };
  }
}

return [{
  json: {
    success: true,
    grant_id: context.grant_id,
    org_id: context.org_id,
    funder_name: context.funder_name,
    totalDocuments: allDocs.length,
    relevantCount: Object.keys(relevantDocs).length,
    documents: relevantDocs,
    narratives: context.narratives,
    sectionsReturned: context.sectionsReturned,
    retrievedAt: new Date().toISOString()
  }
}];
